<head><meta charset="utf-8"><meta name="viewport" content="width=device-width, initial-scale=1"><meta name="csrf-token" content="{{ csrf_token() }}"><title>Administration · Passion Cosmetic</title>@vite(['resources/css/app.css', 'resources/js/admin/main.ts'])</head>
<body><style>.content-workspace{display:grid;gap:1rem;margin-top:1.25rem}.content-section-nav{display:flex;gap:.45rem;overflow:auto;padding:.15rem 0 .5rem}.content-section-nav button{min-height:44px;flex:0 0 auto;border:1px solid var(--line);border-radius:.55rem;background:var(--paper);padding:.55rem .75rem;font:700 .74rem var(--sans);text-align:left}.content-section-nav button.is-selected{border-color:var(--accent-dark);background:var(--pink)}.content-mode-body{min-width:0}.content-guide-tip{margin-top:.75rem!important;padding-top:.75rem;border-top:1px solid var(--line);color:var(--muted);font-size:.78rem}.content-management-page .section-management-layout{display:grid;gap:1rem}.content-management-page .section-management-list>li{box-shadow:0 .25rem .7rem rgb(30 20 23 / .035)}@media(min-width:900px){.content-workspace{grid-template-columns:13.5rem minmax(0,1fr) 17rem;align-items:start}.content-section-nav{position:sticky;top:1rem;display:grid;overflow:visible;padding:0}.content-section-nav button{width:100%}.content-management-context{display:none}.content-section-guide{position:sticky;top:1rem;margin:0}.content-management-page .section-management-layout{grid-template-columns:minmax(19rem,.7fr) minmax(0,1.3fr);align-items:start}.content-management-page .section-management-list{position:sticky;top:1rem}}@media(max-width:899px){.content-section-guide{display:none}.content-management-page .section-management-header{align-items:start;flex-direction:column}.content-management-page .section-management-header .admin-action{width:100%}}</style><style>@media(max-width:899px){.admin-shell>.admin-sidebar{position:sticky;top:0;z-index:40;display:grid;grid-template-columns:minmax(0,1fr) auto;grid-template-areas:"brand profile" "nav nav";gap:.4rem .75rem;min-height:0;padding:.55rem .75rem .45rem!important;border-bottom:1px solid var(--line);box-shadow:0 .45rem 1.2rem rgb(31 20 23 / .08)}.admin-sidebar .admin-brand{grid-area:brand}.admin-sidebar .admin-profile{grid-area:profile;display:flex;align-items:center;gap:.35rem;margin:0;padding:0;border:0}.admin-sidebar .admin-profile span{position:absolute;width:1px;height:1px;margin:-1px;overflow:hidden;clip:rect(0 0 0 0);white-space:nowrap}.admin-sidebar .admin-profile .text-link{min-height:2.75rem;padding:.35rem .15rem;font-size:.65rem;white-space:nowrap}.admin-sidebar nav{display:grid!important;grid-area:nav;grid-template-columns:repeat(4,minmax(0,1fr));gap:.25rem!important;overflow:visible!important;margin:0!important;padding:0!important}.admin-sidebar nav a{display:flex!important;min-width:0;min-height:2.45rem!important;gap:.27rem;justify-content:center;padding:.35rem .2rem!important;font-size:clamp(.6rem,2.1vw,.72rem);text-align:center}.admin-sidebar nav a span{min-width:0;overflow:hidden;text-overflow:ellipsis;white-space:nowrap}.admin-sidebar nav a.router-link-active:before{bottom:.12rem;left:50%;width:calc(100% - .7rem);height:.14rem;transform:translateX(-50%)}}</style><main id="admin-app"></main></body>
</html>
